    public static function get(string $key): string
    {
        return self::library()[$key] ?? self::library()['grid'];
    }

    /** Options list for Filament selects. */
    public static function options(): array
    {
        return collect(array_keys(self::library()))->mapWithKeys(fn ($k) => [$k => ucfirst($k)])->toArray();
    }
